#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10;long long ans;
int n,a[N],siz[N],ql[N],qr[N],m,p[N],fa[N];vector<int> T[N],res;
inline int fnd(int x){return fa[x]==x?x:fa[x]=fnd(fa[x]);}
inline void dfs(int u=1,int f=0)
{
	if(f&&T[u].size()==1){siz[u]=1;ql[u]=++m;qr[u]=m+1;return;}
	for(int v:T[u])if(v!=f){dfs(v,u);siz[u]+=siz[v];}ql[u]=m-siz[u]+1;qr[u]=m+1;
}
int main()
{
	n=read();rep(1,n,i)a[i]=read();
	rep(2,n,i)
	{
		int u=read(),v=read();
		T[u].push_back(v);T[v].push_back(u);
	}
	dfs();rep(1,m+1,i)fa[i]=i;rep(1,n,i)p[i]=i;
	sort(p+1,p+n+1,[&](int x,int y){return a[x]<a[y];});
	for(int l=1,r=1;l<=n;l=r)
	{	
		while(r<=n&&a[p[r]]==a[p[l]])++r;rep(l,r-1,i)if(fnd(ql[p[i]])!=fnd(qr[p[i]]))res.push_back(p[i]);
		rep(l,r-1,i){if(fnd(ql[p[i]])!=fnd(qr[p[i]])){fa[fnd(ql[p[i]])]=fa[fnd(qr[p[i]])];ans+=a[p[i]];}}
	}
	printf("%lld %d\n",ans,int(res.size()));sort(res.begin(),res.end());
	for(int v:res)printf("%d ",v);puts("");
}
